/**
 * @summary Stitcher-wise performance report
 */
export const getGetStitcherPerformanceReportUrl = (
  params?: GetStitcherPerformanceReportParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/reports/stitcher-performance?${stringifiedParams}`
    : `/api/reports/stitcher-performance`;
};

